import java.io.*;

public class CommandInjectionFixedExample {
    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String command = br.readLine();

            // Validate and sanitize the input
            if (!isValidCommand(command)) {
                System.out.println("Invalid command");
                return;
            }

            Process process = Runtime.getRuntime().exec("ping -c 4 " + command);

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static boolean isValidCommand(String command) {
        // Add your validation logic here, for example, allow only alphanumeric characters
        return command.matches("[a-zA-Z0-9]+");
    }
}

